(function () {

    console.log("WIDGET JS LOADED");

    function init() {

        const script = document.querySelector('script[src*="widget"]');
        const botId = script?.getAttribute("data-bot-id");

        if (!botId) {
            console.error("Missing data-bot-id");
            return;
        }

        console.log("Chalpy loaded for bot:", botId);

        const iframe = document.createElement("iframe");
        iframe.src = `https://chalpy-ai.vercel.app/v1/embed/${botId}`;

        iframe.style.position = "fixed";
        iframe.style.bottom = "20px";
        iframe.style.right = "20px";
        iframe.style.width = "320px";
        iframe.style.height = "440px";
        iframe.style.border = "none";
        iframe.style.outline = "none";
        iframe.style.borderRadius = "12px";
        iframe.style.background = "transparent";
        // iframe.style.boxShadow = "0 4px 20px rgba(0,0,0,0.2)";
        iframe.style.display = "block";
        iframe.style.zIndex = "9999";

        document.body.appendChild(iframe);

    }

    window.addEventListener("load", init);

})();